#!/usr/bin/env python3
"""Inspect R34 eval state.json files for feasibility reports, search queries, and narratives."""
import json
import os

BASE = r"G:\PaperAgent\tmp_re34_eval"
ALL_CASES = ["R34-002", "R34-038", "R34-046", "R34-066", "R34-092", "R34-033"]

print("=" * 80)
print("PART 1: R34-046 feasibility_report — check for 硬件/机械臂/hardware")
print("=" * 80)

path_046 = os.path.join(BASE, "R34-046", "state.json")
try:
    with open(path_046, encoding="utf-8") as f:
        state_046 = json.load(f)
    feas_046 = state_046.get("feasibility_report", {})
    print("\nFull feasibility_report dict:")
    print(json.dumps(feas_046, ensure_ascii=False, indent=2))
    # Check values for keywords
    found_046 = []
    for key, val in feas_046.items():
        val_str = str(val)
        for kw in ["硬件", "机械臂", "hardware"]:
            if kw.lower() in val_str.lower():
                found_046.append((key, kw, val_str[:150]))
    if found_046:
        print("\n*** MATCHES FOUND in R34-046 feasibility_report:")
        for key, kw, snippet in found_046:
            print(f"  - Key '{key}' contains '{kw}': {snippet}...")
    else:
        print("\n*** NO MATCHES for 硬件/机械臂/hardware in R34-046 feasibility_report values.")
except Exception as e:
    print(f"ERROR reading R34-046: {e}")

print("\n" + "=" * 80)
print("PART 2: R34-033 feasibility_report — check for 合规/数据/医疗/隐私")
print("=" * 80)

path_033 = os.path.join(BASE, "R34-033", "state.json")
try:
    with open(path_033, encoding="utf-8") as f:
        state_033 = json.load(f)
    feas_033 = state_033.get("feasibility_report", {})
    print("\nFull feasibility_report dict:")
    print(json.dumps(feas_033, ensure_ascii=False, indent=2))
    found_033 = []
    for key, val in feas_033.items():
        val_str = str(val)
        for kw in ["合规", "数据", "医疗", "隐私"]:
            if kw in val_str:
                found_033.append((key, kw, val_str[:150]))
    if found_033:
        print("\n*** MATCHES FOUND in R34-033 feasibility_report:")
        for key, kw, snippet in found_033:
            print(f"  - Key '{key}' contains '{kw}': {snippet}...")
    else:
        print("\n*** NO MATCHES for 合规/数据/医疗/隐私 in R34-033 feasibility_report values.")
except Exception as e:
    print(f"ERROR reading R34-033: {e}")

print("\n" + "=" * 80)
print("PART 3: ALL 6 cases — search_steps queries, flag 'deep learning'")
print("=" * 80)

for case_id in ALL_CASES:
    case_path = os.path.join(BASE, case_id, "state.json")
    print(f"\n--- {case_id} ---")
    try:
        with open(case_path, encoding="utf-8") as f:
            state = json.load(f)
        search_steps = state.get("search_steps", [])
        print(f"  search_steps count: {len(search_steps)}")
        for i, step in enumerate(search_steps):
            query = step.get("query")
            if query is not None:
                print(f"  Step {i}: query = {query}")
                if "deep learning" in str(query).lower():
                    print(f"    *** FLAG: query contains 'deep learning'!")
            else:
                # Print what keys this step has if no query
                print(f"  Step {i}: (no 'query' field) keys={list(step.keys())}")
    except Exception as e:
        print(f"  ERROR: {e}")

print("\n" + "=" * 80)
print("PART 4: ALL 6 cases — research_narratives check (first 200 chars)")
print("=" * 80)

for case_id in ALL_CASES:
    case_path = os.path.join(BASE, case_id, "state.json")
    print(f"\n--- {case_id} ---")
    try:
        with open(case_path, encoding="utf-8") as f:
            state = json.load(f)
        narratives = state.get("research_narratives")
        if narratives is None:
            print("  research_narratives: <field not present / None>")
        elif isinstance(narratives, (list, dict)):
            if isinstance(narratives, list):
                print(f"  research_narratives type: list, length: {len(narratives)}")
            else:
                print(f"  research_narratives type: dict, keys: {len(narratives)}")
            if len(narratives) == 0:
                print("  research_narratives: EMPTY")
            else:
                narr_str = json.dumps(narratives, ensure_ascii=False)
                print(f"  research_narratives (first 200 chars): {narr_str[:200]}")
        elif isinstance(narratives, str):
            if len(narratives.strip()) == 0:
                print("  research_narratives: EMPTY STRING")
            else:
                print(f"  research_narratives (first 200 chars): {narratives[:200]}")
        else:
            print(f"  research_narratives type: {type(narratives).__name__}, value: {str(narratives)[:200]}")
    except Exception as e:
        print(f"  ERROR: {e}")

print("\n" + "=" * 80)
print("DONE")
print("=" * 80)

